// GTM Domain Agent - Core Logic
const input = $input.first().json;
const body = input.body || input;
const goal = body.goal;
const tenant_id = body.tenant_id;

if (!goal || !tenant_id) {
  throw new Error('Missing required fields: goal and tenant_id');
}

const N8N_BASE = 'https://mmurawala.app.n8n.cloud';
const N8N_API_KEY = $vars.N8N_API_KEY;
const ANTHROPIC_API_KEY = $vars.ANTHROPIC_API_KEY_N8N;
const GW_MASTER_KEY = $vars.key_master;
const ACTION_MAP_TABLE = 'nTBOiE9byj3KcHVQ';
const GW_PATH = '/webhook/orchestrate-v2';
const MODEL = 'claude-sonnet-4-6';
const MAX_TURNS = 15;

const actionMapResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${N8N_BASE}/api/v1/data-tables/${ACTION_MAP_TABLE}/rows?limit=200`,
  headers: { 'X-N8N-API-KEY': N8N_API_KEY },
  json: true
});
const actionMap = actionMapResp.data || actionMapResp.rows || [];

const tools = [
  { name: 'list_domain_actions', description: 'Lists all available GTM domain actions from the action map.', input_schema: { type: 'object', properties: {}, required: [] } },
  { name: 'ascend_gateway', description: 'Executes a GTM action through the Ascend Gateway.', input_schema: { type: 'object', properties: { api_name: { type: 'string' }, action: { type: 'string' }, params: { type: 'object' } }, required: ['api_name', 'action'] } },
  { name: 'think', description: 'Think through complex problems step by step.', input_schema: { type: 'object', properties: { thought: { type: 'string' } }, required: ['thought'] } }
];

async function executeTool(name, toolInput) {
  if (name === 'list_domain_actions') return JSON.stringify(actionMap.map(r => ({ api_name: r.api_name, action: r.action, description: r.description || '' })));
  if (name === 'think') return JSON.stringify({ noted: true, thought: toolInput.thought });
  if (name === 'ascend_gateway') {
    try {
      const gwResp = await this.helpers.httpRequest({ method: 'POST', url: `${N8N_BASE}${GW_PATH}`, headers: { 'Content-Type': 'application/json', 'x-api-key': GW_MASTER_KEY }, body: { api_name: toolInput.api_name, action: toolInput.action, tenant_id, params: toolInput.params || {} }, json: true });
      return JSON.stringify(gwResp);
    } catch(e) { return JSON.stringify({ error: e.message }); }
  }
  return JSON.stringify({ error: `Unknown tool: ${name}` });
}

const systemPrompt = `You are the GTM Domain Agent. Help users accomplish GTM tasks by discovering and executing actions through the Ascend Gateway.\n\nWorkflow:\n1. Use list_domain_actions to see available actions\n2. Use think to plan your approach\n3. Use ascend_gateway to execute actions\n4. Summarize results clearly\n\nTenant: ${tenant_id}. Be concise and action-oriented.`;

let messages = [{ role: 'user', content: goal }];
let finalResponse = '';

for (let turn = 0; turn < MAX_TURNS; turn++) {
  const result = await this.helpers.httpRequest({ method: 'POST', url: 'https://api.anthropic.com/v1/messages', headers: { 'Content-Type': 'application/json', 'x-api-key': ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01' }, body: { model: MODEL, max_tokens: 4096, system: systemPrompt, tools, messages }, json: true });
  if (result.error) throw new Error(`Anthropic error: ${JSON.stringify(result.error)}`);
  messages.push({ role: 'assistant', content: result.content });
  if (result.stop_reason === 'end_turn') { finalResponse = result.content.filter(b => b.type === 'text').map(b => b.text).join('\n'); break; }
  const toolUseBlocks = result.content.filter(b => b.type === 'tool_use');
  if (toolUseBlocks.length === 0) { finalResponse = result.content.filter(b => b.type === 'text').map(b => b.text).join('\n'); break; }
  const toolResults = [];
  for (const tu of toolUseBlocks) { const tr = await executeTool.call(this, tu.name, tu.input); toolResults.push({ type: 'tool_result', tool_use_id: tu.id, content: tr }); }
  messages.push({ role: 'user', content: toolResults });
}

return [{ json: { response: finalResponse, tenant_id, goal, turns: messages.length } }];
